sql:
SELECT DISTINCT i.incident_id
FROM incident_images i
INNER JOIN incident_videos v ON i.incident_id = v.incident_id;

SELECT image_caption, image_source
FROM incident_images
WHERE incident_id = 'A-153766';

SELECT MIN(image_timestamp) AS earliest_timestamp
FROM incident_images
WHERE incident_id = 'A-153766';

external_knowledge:
- 'starting times' refers to the earliest media timestamps for each incident; 
- 'media records' may include both images and videos from various sources like police, public, or CCTV footage; 
- 'incidents' are assumed to be events or cases to which these media items are associated, each identified by a unique incident ID.

sql:
SELECT 
  (SELECT COUNT(DISTINCT image_id) FROM incident_images WHERE incident_id = 'A-153766') +
  (SELECT COUNT(DISTINCT video_id) FROM incident_videos WHERE incident_id = 'A-153766') AS total_media_count;

SELECT COUNT(image_id) AS image_count
FROM incident_images
WHERE incident_id = 'A-153766';

external_knowledge:
- 'Police-sourced' refers to images or videos obtained from law enforcement agencies; 
- 'Non-police-sourced' refers to images or videos from any source other than law enforcement, such as drivers or CCTV cameras. 
- The sources considered are limited to 'Police', 'Driver', and 'CCTV' as these are the trusted providers of incident images and videos.

sql:
SELECT incident_id, COUNT(image_id) AS picture_count
FROM incident_images
GROUP BY incident_id;

SELECT incident_id, COUNT(video_id) AS video_count
FROM incident_videos
GROUP BY incident_id;
